var getAllMeal = async (query) => {
  const { search, minPrice, maxPrice, categoryId, providerId } = query;
  return prisma.meal.findMany({
    where: {
      isAvailable: true,
      providerId: providerId || void 0,
      categoryId: categoryId || void 0,
      price: {
        gte: minPrice ? Number(minPrice) : void 0,
        lte: maxPrice ? Number(maxPrice) : void 0
      },
      name: search ? { contains: search, mode: "insensitive" } : void 0
    },
    include: {
      provider: true,
      category: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
};
