// src/modules/order/order.service.ts
var OrderService = {
  // CREATE ORDER (Customer)
  createOrder: async (payload) => {
    const meals = await prisma.meal.findMany({
      where: {
        id: { in: payload.items.map((i) => i.mealId) }
      }
    });
    if (meals.length === 0) {
      throw new Error("Invalid meal items");
    }
    let totalAmount = 0;
    const orderItems = payload.items.map((item) => {
      const meal = meals.find((m) => m.id === item.mealId);
      if (!meal) {
        throw new Error("Meal not found");
      }
      totalAmount += meal.price * item.quantity;
      return {
        mealId: meal.id,
        name: meal.name,
        price: meal.price,
        quantity: item.quantity
      };
    });
    return prisma.order.create({
      data: {
        customerId: payload.customerId,
        providerId: payload.providerId,
        deliveryAddress: payload.deliveryAddress,
        totalAmount,
        items: {
          create: orderItems
        }
      },
      include: {
        items: true
      }
    });
  },
  getOrdersByAdmin: async () => {
    return prisma.order.findMany({
      orderBy: {
        createdAt: "desc"
      }
    });
  },
  // GET ORDERS FOR CUSTOMER
  getOrdersByCustomer: async (customerId) => {
    return prisma.order.findMany({
      where: { customerId },
      include: {
        items: true,
        provider: true
      },
      orderBy: {
        createdAt: "desc"
      }
    });
  },
  // GET ORDERS FOR PROVIDER service 
  getOrdersByProvider: async (providerId) => {
    return prisma.order.findMany({
      where: { providerId },
      include: {
        items: true,
        customer: {
          select: { id: true, name: true, email: true }
        }
      },
      orderBy: {
        createdAt: "desc"
      }
    });
  },
  // GET SINGLE ORDER (Customer / Provider / Admin)
  getOrderById: async (orderId) => {
    return prisma.order.findUnique({
      where: { id: orderId },
      include: {
        items: {
          include: { meal: true }
        },
        customer: true,
        provider: true
      }
    });
  },
  //   // UPDATE ORDER STATUS (Provider)
  updateOrderStatus: async (orderId, providerId, status) => {
    const order = await prisma.order.findFirst({
      where: { id: orderId, providerId }
    });
    if (!order) {
      throw new Error("Order not found or unauthorized");
    }
    return prisma.order.update({
      where: { id: orderId },
      data: { status }
    });
  },
  // provider states 
  // GET PROVIDER ORDER STATS
  getProviderStats: async (providerId) => {
    const totalOrders = await prisma.order.count({
      where: { providerId }
    });
    const pendingOrders = await prisma.order.count({
      where: { providerId, status: "PENDING" }
    });
    const deliveredOrders = await prisma.order.count({
      where: { providerId, status: "DELIVERED" }
    });
    const revenue = await prisma.order.aggregate({
      where: {
        providerId,
        status: "DELIVERED"
      },
      _sum: {
        totalAmount: true
      }
    });
    return {
      totalOrders,
      pendingOrders,
      deliveredOrders,
      totalRevenue: revenue._sum.totalAmount || 0
    };
  }
};

