// src/modules/review/review.service.ts
var createReview = async (payload, customerId) => {
  const meal = await prisma.meal.findUnique({
    where: { id: payload.mealId }
  });
  if (!meal) {
    throw new Error("Meal not found");
  }
  return prisma.review.create({
    data: {
      rating: payload.rating,
      comment: payload.comment,
      meal: {
        connect: { id: payload.mealId }
      },
      customer: {
        connect: { id: customerId }
      }
    }
  });
};
var getReviewsByMeal = async (mealId) => {
  return prisma.review.findMany({
    where: { mealId },
    include: {
      customer: {
        select: {
          id: true,
          name: true
        }
      }
    },
    orderBy: {
      createdAt: "desc"
    }
  });
};
var updateReview = async (reviewId, customerId, payload) => {
  const review = await prisma.review.findUnique({
    where: { id: reviewId }
  });
  if (!review || review.customerId !== customerId) {
    throw new Error("Unauthorized or review not found");
  }
  return prisma.review.update({
    where: { id: reviewId },
    data: payload
  });
};
var deleteReview = async (reviewId, customerId) => {
  const review = await prisma.review.findUnique({
    where: { id: reviewId }
  });
  if (!review || review.customerId !== customerId) {
    throw new Error("Unauthorized or review not found");
  }
  return prisma.review.delete({
    where: { id: reviewId }
  });
};
var reviewService = {
  createReview,
  getReviewsByMeal,
  updateReview,
  deleteReview
};

